/*
 * Extended easing curves for gamut scene CSS.
 *
 * Standard CSS animation-timing-function gives you `ease`, `ease-in`,
 * `ease-out`, `ease-in-out`, `linear`, plus arbitrary `cubic-bezier(...)`
 * and `steps(N)`. This file extends that vocabulary with the standard
 * web-animation eases (easings.net naming) as CSS custom properties.
 *
 * Copy the :root block below into your scene's <style> (or import this
 * file). Then reference any ease as `var(--ease-out-back)` etc.:
 *
 *   #title { animation: slide 1s var(--ease-out-back) forwards; }
 *
 * All values are cubic-bezier approximations of the canonical eases
 * popularized at https://easings.net — same curves used by GSAP's
 * `power*`, `back`, `circ`, `expo`, `quint`, etc. families.
 *
 * Springs / bounces / elastic / rough / wiggle aren't representable as
 * cubic-bezier and aren't included here. For those, lay out the
 * animation as a multi-stop @keyframes timeline by hand — gamut's
 * Stylo animation engine handles per-stop interpolation correctly.
 */

:root {
  /* —— Quadratic */
  --ease-in-quad:        cubic-bezier(0.11, 0,    0.5,  0);
  --ease-out-quad:       cubic-bezier(0.5,  1,    0.89, 1);
  --ease-in-out-quad:    cubic-bezier(0.45, 0,    0.55, 1);

  /* —— Cubic */
  --ease-in-cubic:       cubic-bezier(0.32, 0,    0.67, 0);
  --ease-out-cubic:      cubic-bezier(0.33, 1,    0.68, 1);
  --ease-in-out-cubic:   cubic-bezier(0.65, 0,    0.35, 1);

  /* —— Quartic */
  --ease-in-quart:       cubic-bezier(0.5,  0,    0.75, 0);
  --ease-out-quart:      cubic-bezier(0.25, 1,    0.5,  1);
  --ease-in-out-quart:   cubic-bezier(0.76, 0,    0.24, 1);

  /* —— Quintic */
  --ease-in-quint:       cubic-bezier(0.64, 0,    0.78, 0);
  --ease-out-quint:      cubic-bezier(0.22, 1,    0.36, 1);
  --ease-in-out-quint:   cubic-bezier(0.83, 0,    0.17, 1);

  /* —— Sine */
  --ease-in-sine:        cubic-bezier(0.12, 0,    0.39, 0);
  --ease-out-sine:       cubic-bezier(0.61, 1,    0.88, 1);
  --ease-in-out-sine:    cubic-bezier(0.37, 0,    0.63, 1);

  /* —— Exponential */
  --ease-in-expo:        cubic-bezier(0.7,  0,    0.84, 0);
  --ease-out-expo:       cubic-bezier(0.16, 1,    0.3,  1);
  --ease-in-out-expo:    cubic-bezier(0.87, 0,    0.13, 1);

  /* —— Circular */
  --ease-in-circ:        cubic-bezier(0.55, 0,    1,    0.45);
  --ease-out-circ:       cubic-bezier(0,    0.55, 0.45, 1);
  --ease-in-out-circ:    cubic-bezier(0.85, 0,    0.15, 1);

  /* —— Back (overshoot) */
  --ease-in-back:        cubic-bezier(0.36, 0,    0.66, -0.56);
  --ease-out-back:       cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-in-out-back:    cubic-bezier(0.68, -0.6, 0.32, 1.6);
}

